begin;create extension if not exists pgtap with schema extensions;set local search_path=public,extensions;select plan(21);
insert into auth.users(instance_id,id,aud,role,email,encrypted_password,email_confirmed_at,raw_app_meta_data,raw_user_meta_data,created_at,updated_at,confirmation_token,email_change,email_change_token_new,recovery_token) values('00000000-0000-0000-0000-000000000000','77000000-0000-4000-8000-000000000001','authenticated','authenticated','lifecycle-owner@example.test','',now(),'{}','{"display_name":"Lifecycle Owner"}',now(),now(),'','','','');
set local role authenticated;select set_config('request.jwt.claims','{"sub":"77000000-0000-4000-8000-000000000001","role":"authenticated","email":"lifecycle-owner@example.test","aal":"aal2"}',true);
select lives_ok($$select * from app.create_business_with_owner('Lifecycle Test','lifecycle-test','Main','main','America/Chicago')$$,'tenant created');
select lives_ok($$select app.create_customer_household_with_pet((select id from businesses where public_slug='lifecycle-test'),'Pat','Owner','','lifecycle@example.test',null,'Milo','Mix','2020-01-01',false,'male')$$,'household created');
select lives_ok($$select app.create_service_draft((select id from businesses where public_slug='lifecycle-test'),'boarding','Boarding','Boarding','overnight_date_range',null,'staff_approval','Stay')$$,'service created');
select lives_ok($$select app.add_service_question((select business_id from services),(select id from service_versions),'feeding_notes','Feeding notes','short_text',true,'[]',0)$$,'intake question created');
select lives_ok($$select app.publish_service_version((select business_id from services),(select id from services),(select id from service_versions),(select id from locations),false,true,true,false)$$,'service published');
select lives_ok($$select app.configure_capacity_pool((select business_id from services),(select id from locations),(select id from services),'Boarding capacity','count',2,2)$$,'capacity configured');
select lives_ok($$select * from app.create_pricing_bundle((select id from businesses where public_slug='lifecycle-test'),(select id from locations),'Standard USD','USD','Standard policy','none',0,0,24,5000,10000,'Care agreement','Accepted terms.','No deposit.')$$,'pricing created');
select lives_ok($$select app.add_price_rate((select business_id from price_books),(select id from price_book_versions),(select id from locations),(select id from service_versions),'night',10000,'Boarding night',100,null,null)$$,'rate created');
select lives_ok($$select app.publish_pricing_bundle((select business_id from price_books),(select id from price_book_versions),(select id from commercial_policy_versions),current_date)$$,'pricing published');
select lives_ok($$select app.create_booking_request((select business_id from services),(select id from locations),(select id from customers),(select id from pets),(select id from services),now()+interval '2 days',now()+interval '4 days',1,2,null,'staff','lifecycle-booking')$$,'booking requested');
select is(app.sync_booking_action_items((select business_id from bookings),(select id from bookings)),1,'current action materialized once');
select is(app.sync_booking_action_items((select business_id from bookings),(select id from bookings)),0,'action sync is idempotent');
select lives_ok($$select app.save_booking_intake_answer((select business_id from bookings),(select id from bookings),(select id from service_booking_questions),to_jsonb('Two cups daily'::text),'answer-001')$$,'intake answer captured');
select is(app.save_booking_intake_answer((select business_id from bookings),(select id from bookings),(select id from service_booking_questions),to_jsonb('Two cups daily'::text),'answer-001'),(select id from booking_intake_answers),'intake retry is idempotent');
select lives_ok($$select app.save_booking_intake_answer((select business_id from bookings),(select id from bookings),(select id from service_booking_questions),to_jsonb('One cup twice daily'::text),'answer-002')$$,'corrected intake answer captured');
select is((select count(*) from booking_intake_answers),2::bigint,'answer history is append-only');
select is((select supersedes_answer_id from booking_intake_answers where idempotency_key='answer-002'),(select id from booking_intake_answers where idempotency_key='answer-001'),'correction links prior answer');
select throws_ok($$select app.mark_booking_no_show((select business_id from bookings),(select id from bookings),'Customer did not arrive','early-no-show')$$,'22023','booking has not started','future booking cannot be marked no-show');
select lives_ok($$update capacity_holds set expires_at=now()-interval '1 minute' where status='active';select app.expire_booking_requests((select business_id from bookings))$$,'stale request expiry runs');
select is((select status from bookings),'expired','stale request closes explicitly');
select is((select status from booking_action_items),'expired','open action expires with request');
select * from finish();rollback;
